sql:
SELECT MAX(price) AS max_price
FROM sponsorship_plans
WHERE event_id = 1;

SELECT COUNT(sponsor_id) AS total_sponsors
FROM sponsors
WHERE event_id = 1;

external_knowledge:
- In this context, having more than two sponsors is a measure of an event's popularity or success in securing funding; 
- The number of sponsors can indicate the level of community or corporate support for an event; 
- Events with multiple sponsors may offer a variety of activities or have a broad appeal.

sql:
SELECT event_id, COUNT(sponsor_id) AS sponsor_count
FROM sponsors
GROUP BY event_id;

SELECT COUNT(plan_id) AS plan_count
FROM sponsorship_plans
WHERE event_id = 1;

SELECT plan_name, price
FROM sponsorship_plans
WHERE DATE('now') BETWEEN start_date AND end_date;

SELECT SUM(total_amount) AS total_due
FROM invoices
WHERE event_id = (SELECT event_id FROM event_details WHERE event_name = 'Annual Conference');

SELECT event_name
FROM event_details
WHERE event_date > DATE('now');

SELECT event_name
FROM event_details
ORDER BY event_date DESC;

SELECT event_name
FROM event_details
WHERE event_id = 0;

SELECT MIN(price) AS min_sponsorship_price
  FROM sponsorship_plans
  WHERE event_id = (SELECT event_id FROM event_details WHERE event_name = 'Annual Conference');
